using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = JsonSerializer.IsReflectionEnabledByDefault
        ? new DefaultJsonTypeInfoResolver()
        : throw new InvalidOperationException("Reflection disabled"),
    WriteIndented = true
};

// ── 1. Strongly-typed metadata: GetTypeInfo<T>() ──────────────────
//    Returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Type handled  : {personInfo.Type.Name}");
Console.WriteLine($"Kind          : {personInfo.Kind}");
Console.WriteLine($"Properties    : {string.Join(", ", personInfo.Properties.Select(p => p.Name))}");
Console.WriteLine();

// Round-trip with the typed metadata
var alice = new Person("Alice", 30);
string json = JsonSerializer.Serialize(alice, personInfo);
Console.WriteLine($"Serialized    : {json}");
Person? back = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"Deserialized  : {back}");
Console.WriteLine();

// ── 2. Probe without throwing: TryGetTypeInfo() ───────────────────
//    Returns false instead of throwing when metadata isn't available.
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"TryGet Person : YES — {found!.Type.Name}");
else
    Console.WriteLine("TryGet Person : NO");

// Stream is intentionally NOT resolvable by the default resolver
// (it's abstract with no known derived types), so this returns false.
if (options.TryGetTypeInfo(typeof(Stream), out _))
    Console.WriteLine("TryGet Stream : YES");
else
    Console.WriteLine("TryGet Stream : NO  — metadata not available (no exception thrown)");

